import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js"

describe("drain sink abort", () => {
  it("should call read with abort when sink.abort() is called after read is set", (done) => {
    // Create a source that tracks whether it was aborted
    let abortCalled = false;
    let readCallCount = 0;

    function source(end: any, cb: Function) {
      readCallCount++;
      if (end) {
        abortCalled = true;
        cb(end, null);
        return;
      }
      // Simulate async data
      setTimeout(() => {
        cb(null, readCallCount);
      }, 10);
    }

    const sink = drain(
      (data: any) => {
        // After first data, abort the stream
        if (data === 1) {
          sink.abort(new Error("test abort"), (err: any) => {
            // The abort callback should be called when original code runs
            // In mutated code, read is never called with abort, so this callback may never fire
            expect(abortCalled).toBe(true);
            done();
          });
        }
      },
      (err: any) => {
        // done callback - may be called
      }
    );

    sink(source);

    // Timeout to detect if abort callback was never called (mutation case)
    const timeout = setTimeout(() => {
      if (!abortCalled) {
        done(new Error("abort was never called on read - mutation detected"));
      }
    }, 500);

    // Clean up timeout if test completes normally
    const originalDone = done;
  });
});
```

Wait, I need to reconsider. The mutation changes `if(read)` to `if(false)`, so when `sink.abort()` is called after `read` has been set, the original code would call `read(abort, cb)` but the mutated code would not. Let me write a cleaner test:

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js"

describe("drain sink abort", () => {
  it("should invoke the abort callback when abort is called after read is assigned", (done) => {
    let abortCallbackCalled = false;

    // A synchronous source that always provides data
    function source(end: any, cb: Function) {
      if (end) {
        // Signal end acknowledged
        cb(end, null);
        return;
      }
      // Provide data synchronously - but we'll abort before consuming
      cb(null, 42);
    }

    const sink = drain(
      (data: any) => {
        // Return false to stop, but we want to test abort specifically
        return false;
      },
      (err: any) => {
        // normal done
      }
    );

    // Connect source to sink (this sets read = source internally)
    sink(source);

    // Now abort - in original code, this calls read(abort, cb)
    // In mutated code (if(false)), read is never called, so cb is never invoked
    sink.abort(null, (err: any) => {
      abortCallbackCalled = true;
      // In original: read is called with abort, which calls cb, which is this function
      done();
    });

    // If the callback was not called synchronously (source is sync), fail
    setTimeout(() => {
      if (!abortCallbackCalled) {
        done(new Error("abort callback was never called - likely mutated code"));
      }
    }, 100);
  });
});
```

