        cb(end, null);
        return;
      }
      // Never provide data (simulate async source that hasn't responded yet)
      // This means the drain loop is waiting, cbed=false, loop=false
    }

    const sink = drain(
      (_data: any) => { /* no-op op */ },
      (_err: any) => { /* no-op done */ }
    );

    // Connect source to sink - sets read = source internally
    // Since source never calls back synchronously, the while loop exits with loop=false
    sink(source);

    // Now call abort with a callback
    // Original: if(read) return read(abort, cb || function(){}) => calls source with abort=true, source calls cb(true, null)
